1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Customer = { yearsWithMHPCO: number };
3	type QuoteInput = {
4	  customer: Customer;
5	  items: Item[];
6	  previousContracts: number;
7	};
8	
9	const PROCESSING_FEE = 5;
10	const NEWCOMER_PER_ITEM_SURCHARGE_RATE = 0.1;
11	const CURSED_SURCHARGE_RATE = 0.5;
12	
13	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const basePremiumForItem = (item: Item): number =>
23	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
24	
25	const isNewcomer = (customer: Customer): boolean =>
26	  customer.yearsWithMHPCO === 0;
27	
28	const premiumForItem = (item: Item, customer: Customer): number => {
29	  const base = basePremiumForItem(item);
30	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
31	  const newcomerSurcharge = isNewcomer(customer) ? base * NEWCOMER_PER_ITEM_SURCHARGE_RATE : 0;
32	  return base + cursedSurcharge + newcomerSurcharge;
33	};
34	
35	export const quote = (input: QuoteInput): { premium: number } => {
36	  const itemsTotal = input.items.reduce(
37	    (sum, item) => sum + premiumForItem(item, input.customer),
38	    0,
39	  );
40	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
41	};
42	
43	export const claim = (_input: unknown): unknown => {
44	  return undefined;
45	};
